import{_ as e,a as t,b as n,c as i,d,e as l}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as s,o as r,c as u,a2 as p}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"IP Geolocation dan User Management","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/ip-geolocation-and-user-management.md","filePath":"id-ID/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),o={name:"id-ID/Other/ip-geolocation-and-user-management.md"};function m(k,a,c,g,h,b){return r(),u("div",null,[...a[0]||(a[0]=[p('<h1 id="ip-geolocation-dan-user-management" tabindex="-1">IP Geolocation dan User Management <a class="header-anchor" href="#ip-geolocation-dan-user-management" aria-label="Permalink to &quot;IP Geolocation dan User Management&quot;">​</a></h1><p>IP geolocation mengubah alamat IP di catatan uploader, login devices, dan log sejenis menjadi perkiraan lokasi.</p><p>Setelah dikonfigurasi, panel admin bisa menampilkan asal upload dan akses dengan lebih jelas. User Management juga memungkinkan Anda memblokir atau memulihkan akses upload untuk alamat IP yang mencurigakan.</p><h2 id="lokasi-pengaturan" tabindex="-1">Lokasi Pengaturan <a class="header-anchor" href="#lokasi-pengaturan" aria-label="Permalink to &quot;Lokasi Pengaturan&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+e+`" alt="IP geolocation" loading="lazy"></p><h2 id="pengaturan-yang-tersedia" tabindex="-1">Pengaturan yang Tersedia <a class="header-anchor" href="#pengaturan-yang-tersedia" aria-label="Permalink to &quot;Pengaturan yang Tersedia&quot;">​</a></h2><p>Alur IP geolocation terbaru mendukung beberapa sumber, bukan hanya bergantung pada satu layanan peta.</p><table tabindex="0"><thead><tr><th>Pengaturan</th><th>Fungsi</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Memilih bahasa tampilan, misalnya English, Simplified Chinese, Japanese, French, dan lainnya.</td></tr><tr><td>MaxMind Account ID</td><td>Account ID MaxMind untuk MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>License Key MaxMind.</td></tr><tr><td>Tencent Map Key</td><td>Key Tencent Location Service. Berguna untuk alamat China dan IP China daratan.</td></tr><tr><td>ipapi Key</td><td>Key APILayer ipapi. Mendukung IP geolocation multibahasa.</td></tr></tbody></table><p>Isi hanya layanan yang Anda perlukan. Tidak semua field harus dikonfigurasi.</p><p>Jika tidak ada key yang diisi, ImgBed tetap mencoba sumber gratis bawaan, tetapi stabilitas, dukungan bahasa, dan presisinya mungkin lebih rendah dibanding layanan yang Anda konfigurasi sendiri.</p><h2 id="pilihan-yang-disarankan" tabindex="-1">Pilihan yang Disarankan <a class="header-anchor" href="#pilihan-yang-disarankan" aria-label="Permalink to &quot;Pilihan yang Disarankan&quot;">​</a></h2><p>Jika kebutuhan utama Anda adalah alamat China:</p><ol><li>Atur IP geolocation language ke Simplified Chinese.</li><li>Konfigurasikan Tencent Map Key.</li><li>Opsional, tambahkan MaxMind atau ipapi sebagai fallback source.</li></ol><p>Jika kebutuhan utama Anda adalah alamat English atau multibahasa:</p><ol><li>Pilih bahasa yang dibutuhkan.</li><li>Konfigurasikan MaxMind Account ID dan License Key.</li><li>Tambahkan ipapi Key jika butuh hasil multibahasa yang lebih baik.</li></ol><h2 id="setup-maxmind" tabindex="-1">Setup MaxMind <a class="header-anchor" href="#setup-maxmind" aria-label="Permalink to &quot;Setup MaxMind&quot;">​</a></h2><p>MaxMind membutuhkan:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Cari account ID di dashboard MaxMind, lalu buat License Key dari halaman License Keys.</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>Setelah dibuat, tempelkan Account ID dan License Key ke ImgBed, lalu simpan.</p><p>Paket gratis MaxMind cukup untuk penggunaan harian, tetapi tetap memiliki batas request. Jika kuota habis, ImgBed akan melanjutkan dengan mencoba sumber lain yang tersedia.</p><h2 id="setup-ipapi" tabindex="-1">Setup ipapi <a class="header-anchor" href="#setup-ipapi" aria-label="Permalink to &quot;Setup ipapi&quot;">​</a></h2><p>ipapi memakai API Key dari APILayer.</p><p>Buka console ipapi dan salin API Key yang ditampilkan di sana.</p><p><img src="'+n+'" alt="ipapi config" loading="lazy"></p><p>Tempelkan ke field <code>ipapi Key</code> di ImgBed, lalu simpan.</p><p>ipapi mendukung IP geolocation multibahasa dan berguna saat Anda ingin alamat tampil dalam bahasa tertentu. Paket gratisnya juga memiliki batas request. Jika kuota habis, ImgBed akan mencoba sumber lain yang tersedia.</p><h2 id="setup-tencent-map-key" tabindex="-1">Setup Tencent Map Key <a class="header-anchor" href="#setup-tencent-map-key" aria-label="Permalink to &quot;Setup Tencent Map Key&quot;">​</a></h2><p>Tencent Map Key berguna untuk alamat China, terutama IP China daratan.</p><p>Saat membuat key di Tencent Location Service, aktifkan:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Setelah dibuat, tempelkan key ke <code>Tencent Map Key</code>, lalu simpan.</p><p>Jika hanya membutuhkan IP geolocation China dasar, Tencent Map Key sudah cukup untuk memulai.</p><h2 id="yang-perlu-dicek-di-user-management" tabindex="-1">Yang Perlu Dicek di User Management <a class="header-anchor" href="#yang-perlu-dicek-di-user-management" aria-label="Permalink to &quot;Yang Perlu Dicek di User Management&quot;">​</a></h2><p>User Management bisa dibuka dari bagian atas panel admin.</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management menampilkan aktivitas upload berdasarkan IP:</p><table tabindex="0"><thead><tr><th>Field</th><th>Keterangan</th></tr></thead><tbody><tr><td>IP source</td><td>IP asal uploader.</td></tr><tr><td>Address</td><td>Perkiraan lokasi yang didapat dari IP.</td></tr><tr><td>Total upload size</td><td>Total ukuran file yang diupload dari IP ini.</td></tr><tr><td>Upload count</td><td>Jumlah upload dari IP ini.</td></tr><tr><td>Upload allowed</td><td>Aktif berarti upload diizinkan. Nonaktif berarti upload diblokir.</td></tr></tbody></table><p>Klik panah di sebelah kiri untuk membuka daftar file yang diupload oleh IP tersebut.</p><p>Daftar file menampilkan nama file, preview, ukuran file, hasil moderation, status file, dan waktu upload. Jika aktivitas upload terlihat mencurigakan, buka detail IP lebih dulu, tinjau filenya, lalu putuskan apakah upload berikutnya perlu diblokir.</p><p>Jika sebuah IP mencurigakan, matikan <code>Upload allowed</code>. Upload berikutnya dari IP tersebut akan diblokir.</p><h2 id="search-sort-dan-advanced-filters" tabindex="-1">Search, Sort, dan Advanced Filters <a class="header-anchor" href="#search-sort-dan-advanced-filters" aria-label="Permalink to &quot;Search, Sort, dan Advanced Filters&quot;">​</a></h2><p>Di bagian atas User Management, cari berdasarkan IP source atau address.</p><p>Urutkan berdasarkan waktu, upload count, atau total upload size untuk menemukan uploader terbaru, uploader dengan frekuensi tinggi, atau IP dengan pemakaian besar.</p><p>Untuk investigasi lebih detail, buka advanced filters.</p><p><img src="'+d+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters mendukung:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Penggunaan</th></tr></thead><tbody><tr><td>Time range</td><td>Menampilkan IP yang mengupload file dalam periode tertentu.</td></tr><tr><td>Access status</td><td>Memfilter berdasarkan status normal, blocked, dan status sejenis.</td></tr><tr><td>Allow/block list</td><td>Memfilter berdasarkan allowlist, blocklist, atau belum diatur.</td></tr><tr><td>File type</td><td>Menampilkan IP yang mengupload gambar, video, audio, dokumen, kode, atau file lain.</td></tr><tr><td>File size</td><td>Memfilter berdasarkan rentang ukuran file yang diupload.</td></tr><tr><td>Age rating</td><td>Memfilter berdasarkan unset, General, R12+, R16+, R18, dan rating sejenis.</td></tr><tr><td>File status</td><td>Memfilter berdasarkan status file saat ini untuk menelusuri file bermasalah.</td></tr></tbody></table><p>Klik <code>Apply Filters</code> untuk menerapkan filter. Gunakan <code>Reset</code> untuk kembali ke semua data.</p><h2 id="tampilan-mobile" tabindex="-1">Tampilan Mobile <a class="header-anchor" href="#tampilan-mobile" aria-label="Permalink to &quot;Tampilan Mobile&quot;">​</a></h2><p>Di mobile, User Management berubah menjadi layout card.</p><p><img src="'+l+`" alt="Mobile user management" loading="lazy"></p><p>Setiap card menampilkan IP, address, total upload size, upload count, dan switch upload allowed. Anda bisa mengelola pengguna tanpa perlu menggeser tabel secara horizontal.</p><h2 id="jika-lokasi-terlihat-salah" tabindex="-1">Jika Lokasi Terlihat Salah <a class="header-anchor" href="#jika-lokasi-terlihat-salah" aria-label="Permalink to &quot;Jika Lokasi Terlihat Salah&quot;">​</a></h2><p>IP geolocation bersifat perkiraan. Ini bukan alamat jalan yang presisi.</p><p>Jika pengguna memakai proxy, data center, cloud server, atau jaringan lintas negara, lokasi yang ditampilkan bisa berbeda dari lokasi sebenarnya.</p><p>Gunakan fitur ini untuk memahami asal secara kasar, menemukan upload abnormal, dan membantu keputusan pemblokiran. Jangan memperlakukannya sebagai pelacakan presisi.</p><h2 id="kasus-umum" tabindex="-1">Kasus Umum <a class="header-anchor" href="#kasus-umum" aria-label="Permalink to &quot;Kasus Umum&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kasus</th><th>Arti</th></tr></thead><tbody><tr><td>Address kosong</td><td>IP mungkin belum berhasil di-resolve, atau sumber yang dipakai sedang tidak tersedia.</td></tr><tr><td>Bahasa address salah</td><td>Periksa IP geolocation language dan apakah sumber yang mendukung bahasa tersebut sudah dikonfigurasi.</td></tr><tr><td>Address menunjukkan data center</td><td>Banyak proxy, cloud server, dan crawler muncul sebagai alamat data center atau ISP.</td></tr><tr><td>Upload count tinggi</td><td>Tinjau IP ini dengan teliti dan blokir upload jika perlu.</td></tr><tr><td>Total upload size besar</td><td>Urutkan atau filter, buka detail IP, lalu periksa file tertentu.</td></tr><tr><td>Perlu memulihkan setelah diblokir</td><td>Aktifkan kembali <code>Upload allowed</code>.</td></tr></tbody></table><h2 id="alur-cepat" tabindex="-1">Alur Cepat <a class="header-anchor" href="#alur-cepat" aria-label="Permalink to &quot;Alur Cepat&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka IP Geolocation di Other Settings</span></span>
<span class="line"><span>-&gt; Pilih IP geolocation language</span></span>
<span class="line"><span>-&gt; Isi credential MaxMind, Tencent Map, atau ipapi sesuai kebutuhan</span></span>
<span class="line"><span>-&gt; Simpan pengaturan</span></span>
<span class="line"><span>-&gt; Buka User Management</span></span>
<span class="line"><span>-&gt; Tinjau IP source, address, total upload size, dan upload count</span></span>
<span class="line"><span>-&gt; Gunakan search, sort, atau advanced filters untuk menemukan IP abnormal</span></span>
<span class="line"><span>-&gt; Izinkan atau blokir upload sesuai kebutuhan</span></span></code></pre></div>`,64)])])}const I=s(o,[["render",m]]);export{f as __pageData,I as default};
